{
    if (n <= 1) return n; // base case

    if (cache.count(n)) // ALREADY computed — return the cached answer
    {
        return cache[n];
    }

    long long result = fibonacci(n - 1) + fibonacci(n - 2);
    cache[n] = result; // remember it for next time
    return result;
}

