#include <iostream>
#include <vector>

using namespace std;

int climbStairsHelper(int n, vector<int>& memo)
{
    if (n <= 2) return n;
    if (memo[n] != -1) return memo[n]; // check cache first

    memo[n] = climbStairsHelper(n - 1, memo) + climbStairsHelper(n - 2, memo); // store before returning
    return memo[n];
}

int climbStairs(int n)
{
    vector<int> memo(n + 1, -1);
    return climbStairsHelper(n, memo);
}

int main()
{
    cout << climbStairs(5);

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int robHelper(int i, vector<int>& nums)
{
    if (i < 0) return 0;
    if (i == 0) return nums[0];
    return max(robHelper(i - 1, nums), robHelper(i - 2, nums) + nums[i]);
}

int rob(vector<int>& nums)
{
    return robHelper((int)nums.size() - 1, nums);
}

int main()
{
    vector<int> nums = {2, 7, 9, 3, 1};
    cout << rob(nums);

    return 0;
}

